 1	import React, { FC, useState } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import {
 5	  Button,
 6	  InputGroup,
 7	  InputGroupItem,
 8	  KeyTypes,
 9	  Label,
10	  LabelGroup,
11	  Stack,
12	  TextInput,
13	} from '@patternfly/react-core';
14	
15	type AffinityEditRowValuesProps = {
16	  isHidden?: boolean;
17	  onClear?: () => void;
18	  onSelect?: (event, selection) => void;
19	  values: string[];
20	};
21	
22	export const AffinityEditRowValues: FC<AffinityEditRowValuesProps> = ({
23	  isHidden,
24	  onClear,
25	  onSelect,
26	  values,
27	}) => {
28	  const { t } = useKubevirtTranslation();
29	  const [inputValue, setInputValue] = useState('');
30	
31	  const onClose = (value: string) => {
32	    onSelect(null, value);
33	  };
34	
35	  const onAdd = () => {
36	    onSelect(null, inputValue);
37	    setInputValue('');
38	  };
39	
40	  const addingIsDisabled =
41	    !inputValue || values.some((val) => val.toLowerCase() === inputValue.toLowerCase());
42	
43	  const textInputPlaceholder = t('Enter value');
44	  const labelsToShowCount = Number.MAX_VALUE; // always show all labels
45	
46	  if (isHidden) return null;
47	
48	  return (
49	    <Stack hasGutter>
50	      <LabelGroup isClosable numLabels={labelsToShowCount} onClick={onClear}>
51	        {values.map((value) => (
52	          <Label id={value} key={value} onClose={() => onClose(value)} variant="outline">
53	            {value}
54	          </Label>
55	        ))}
56	      </LabelGroup>
57	      <InputGroup>
58	        <InputGroupItem isFill>
59	          <TextInput
60	            onKeyDown={(event) => {
61	              if (event.key === KeyTypes.Enter && !addingIsDisabled) {
62	                event.preventDefault();
63	                onAdd();
64	              }
65	            }}
66	            aria-label={textInputPlaceholder}
67	            onChange={(_event, value) => setInputValue(value)}
68	            placeholder={textInputPlaceholder}
69	            type="text"
70	            value={inputValue}
71	          />
72	        </InputGroupItem>
73	        <InputGroupItem>
74	          <Button isDisabled={addingIsDisabled} onClick={onAdd} variant="control">
75	            {t('Add')}
76	          </Button>
77	        </InputGroupItem>
78	      </InputGroup>
79	    </Stack>
80	  );
81	};

